  1→import React, { useCallback, useEffect, useRef, useState } from 'react';
  2→import { addons } from 'storybook/internal/manager-api';
  3→import { useStorybookState } from 'storybook/internal/manager-api';
  4→import { EVENTS } from './constants';
  5→import { useIndexedDB } from './useIndexedDB';
  6→import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
  7→import JSON5 from 'json5';
  8→
  9→function idbKeyFor(storyId: string) {
 10→  return `sdui-json-${storyId}`;
 11→}
 12→
 13→function getChannel() {
 14→  try { return addons.getChannel(); } catch { return null; }
 15→}
 16→
 17→function tryParse(text: string): { parsed: any; error: string | null } {
 18→  try {
 19→    return { parsed: JSON.parse(text), error: null };
 20→  } catch {
 21→    try {
 22→      return { parsed: JSON5.parse(text), error: null };
 23→    } catch (e) {
 24→      return { parsed: null, error: (e as Error).message };
 25→    }
 26→  }
 27→}
 28→
 29→function getIsDarkMode(): boolean {
 30→  if (typeof localStorage === 'undefined') return false;
 31→  const stored = localStorage.getItem('sb-ui-theme');
 32→  if (stored) return stored === 'dark';
 33→  return typeof window !== 'undefined'
 34→    && window.matchMedia?.('(prefers-color-scheme: dark)').matches;
 35→}
