 37→export function JsonEditorPanel() {
 38→  const state = useStorybookState();
 39→  const storyId = state.storyId ?? '';
 40→  const [isDarkMode, setIsDarkMode] = useState(getIsDarkMode);
 41→
 42→  const [defaultJson, setDefaultJson] = useState<string>('');
 43→  const [text, setText] = useState<string>('');
 44→  const [error, setError] = useState<string | null>(null);
 45→  const [dirty, setDirty] = useState(false);
 46→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 47→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 48→  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
 49→  const initializedRef = useRef(false);
 50→  const defaultJsonRef = useRef('');
 51→
 52→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 53→
 54→  useEffect(() => {
 55→    const interval = setInterval(() => {
 56→      setIsDarkMode(getIsDarkMode());
 57→    }, 1000);
 58→    return () => {
 59→      clearInterval(interval);
 60→      if (debounceRef.current) clearTimeout(debounceRef.current);
 61→      if (retryRef.current) clearInterval(retryRef.current);
 62→    };
 63→  }, []);
 64→
 65→  useEffect(() => {
 66→    if (debounceRef.current) {
 67→      clearTimeout(debounceRef.current);
 68→      debounceRef.current = null;
 69→    }
 70→    setDefaultJson('');
 71→    defaultJsonRef.current = '';
 72→    setText('');
 73→    setDirty(false);
 74→    setError(null);
 75→    initializedRef.current = false;
 76→  }, [storyId]);
 77→
 78→  useEffect(() => {
 79→    const channel = getChannel();
 80→    if (!channel) return;
 81→
 82→    const onSetDefault = (json: string) => {
 83→      setDefaultJson(json);
 84→      defaultJsonRef.current = json;
 85→      if (retryRef.current) {
 86→        clearInterval(retryRef.current);
 87→        retryRef.current = null;
 88→      }
 89→    };
 90→
 91→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 92→    channel.emit(EVENTS.REQUEST_DEFAULT);
 93→
 94→    let retryCount = 0;
 95→    retryRef.current = setInterval(() => {
 96→      retryCount++;
 97→      if (retryCount > 40) {
 98→        if (retryRef.current) clearInterval(retryRef.current);
 99→        return;
100→      }
101→      channel.emit(EVENTS.REQUEST_DEFAULT);
102→    }, 200);
103→
104→    return () => {
105→      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
106→      if (retryRef.current) {
107→        clearInterval(retryRef.current);
108→        retryRef.current = null;
109→      }
110→    };
111→  }, [storyId]);
112→
113→  useEffect(() => {
114→    if (!ready || !defaultJson) return;
115→    if (initializedRef.current) return;
116→    initializedRef.current = true;
117→    const initial = stored ?? defaultJson;
118→    setText(initial);
119→    editorRef.current?.setValue(initial);
120→    setDirty(!!stored);
121→    setError(null);
122→    // eslint-disable-next-line react-hooks/exhaustive-deps
123→  }, [ready, defaultJson, storyId]);
124→
125→  const handleChange = useCallback(
126→    (value: string) => {
127→      setText(value);
128→
129→      if (debounceRef.current) clearTimeout(debounceRef.current);
130→
131→      debounceRef.current = setTimeout(() => {
132→        const { parsed } = tryParse(value);
133→        if (parsed !== null) {
134→          save(value);
135→          setDirty(value !== defaultJsonRef.current);
136→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
137→        } else {
138→          save(value);
139→          setDirty(true);
140→        }
141→      }, 400);
142→    },
143→    [save],
144→  );
145→
146→  const handleValidationChange = useCallback(
147→    (hasErrors: boolean, message: string | null) => {
148→      setError(hasErrors ? message : null);
149→    },
150→    [],
151→  );
152→
153→  const handleReset = useCallback(() => {
154→    remove();
155→    setText(defaultJson);
156→    editorRef.current?.setValue(defaultJson);
157→    setDirty(false);
158→    setError(null);
159→    const { parsed } = tryParse(defaultJson);
160→    if (parsed !== null) {
161→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
162→    }
163→  }, [defaultJson, remove]);
164→
165→  const handleFormat = useCallback(() => {
166→    const currentText = editorRef.current?.getValue() ?? '';
167→    const { parsed, error: parseErr } = tryParse(currentText);
168→    if (parsed !== null) {
169→      const formatted = JSON.stringify(parsed, null, 2);
170→      setText(formatted);
171→      editorRef.current?.setValue(formatted);
172→      save(formatted);
173→      setDirty(formatted !== defaultJsonRef.current);
174→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
175→      setError(null);
176→    } else {
177→      setError(parseErr);
178→    }
179→  }, [save]);
180→
181→  const s = isDarkMode ? darkStyles : lightStyles;
182→
183→  if (!storyId) {
184→    return <div style={s.empty}>Select a story to edit its JSON.</div>;
185→  }
186→
187→  const isWaiting = !defaultJson && !text;
188→
189→  return (
190→    <div style={s.container}>
191→      <div style={s.toolbar}>
192→        <span style={s.label}>
193→          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
194→        </span>
195→        <div style={s.actions}>
196→          <button
197→            style={s.btn}
198→            onClick={handleFormat}
199→            title="Format & normalize to strict JSON"
200→          >
201→            Format
202→          </button>
203→          <button
204→            style={{ ...s.btn, ...(dirty ? s.btnReset : s.btnDisabled) }}
205→            onClick={handleReset}
206→            disabled={!dirty}
207→            title="Reset to story default"
208→          >
209→            Reset
210→          </button>
211→        </div>
212→      </div>
213→
214→      {error && !isWaiting && <div style={s.error}>{error}</div>}
215→
216→      {isWaiting ? (
217→        <div style={s.empty}>
218→          Waiting for story to send SDUI JSON…
219→          <br />
220→          <span style={{ fontSize: 11, opacity: 0.7 }}>
221→            If this persists, the current story may not use useSDUIJsonEditor().
222→          </span>
223→        </div>
224→      ) : (
225→        <div style={s.editorContainer}>
226→          <CodeMirrorEditor
227→            ref={editorRef}
228→            value={text}
229→            onChange={handleChange}
230→            onValidationChange={handleValidationChange}
231→            isDarkMode={isDarkMode}
232→          />
233→        </div>
234→      )}
235→    </div>
236→  );
237→}
